const page_proxy = require("@xtalk/substrate/page-proxy.js")

const proxy_base = require("@xtalk/db/node/proxy-base.js")

const kernel_base = require("@xtalk/db/node/kernel-base.js")

const kernel_supabase = require("@xtalk/db/node/kernel-supabase.js")

const client_base = require("@xtalk/db/node/client-base.js")

const proxy_supabase = require("@xtalk/db/node/proxy-supabase.js")

const proxy_util = require("@xtalk/db/node/proxy-util.js")

const substrate = require("@xtalk/substrate/substrate.js")

const browser_transport = require("@xtalk/substrate/transport-browser.js")

var DEFAULT_TRANSPORT = "xt.db.default.transport";

var DEFAULT_WORKER = "xt.db.default.worker";

function init_server(node){
  page_proxy.install(node);
  kernel_base.init_handlers(node);
  kernel_supabase.init_handlers(node);
}

function init_server_proxy(node){
  page_proxy.install(node);
  proxy_base.init_proxy_handlers(node);
  proxy_supabase.init_proxy_handlers(node);
}

function sharedworker_init_kernel(node,transport_id,worker_id){
  init_server(node);
  globalThis["onconnect"] = (function (e){
    let port = e["ports"][0];
    port.start();
    return browser_transport.boot_self(node,{
      "transport_id":transport_id || DEFAULT_TRANSPORT,
      "target":port,
      "ready":{
            "signal":"ready",
            "transport":transport_id || DEFAULT_TRANSPORT,
            "worker":transport_id || DEFAULT_WORKER
          }
    });
  });
}

